PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rism: <https://rism.online/api/v1#>
PREFIX pmo: <http://performedmusicontology.org/ontology/>
PREFIX dcterms: <http://purl.org/dc/terms/>
PREFIX relators: <http://id.loc.gov/vocabulary/relators/>
PREFIX schemaorg: <https://schema.org/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?source ?composer ?title ?from ?to WHERE {
        ?source a rism:Source ;
        dcterms:creator [ rdfs:label ?composer ] ;
        rdfs:label ?title ;
        rism:hasDates [ rism:earliestDate ?from ;
             rism:latestDate ?to ];
}

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rism: <https://rism.online/api/v1#>
PREFIX pmo: <http://performedmusicontology.org/ontology/>
PREFIX dcterms: <http://purl.org/dc/terms/>
PREFIX relators: <http://id.loc.gov/vocabulary/relators/>
PREFIX schemaorg: <https://schema.org/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
	?keysig (COUNT(?keysig) as ?total)
	(COUNT(?binaryK) as ?binary)
	((ROUND(?binary / ?total * 100) / 100) as ?br)
	(COUNT(?ternaryK) as ?ternary)
	((ROUND(?ternary / ?total * 100) / 100) as ?tr)
	(COUNT(?compoundK) as ?compound)
	((ROUND(?compound / ?total * 100) / 100) as ?cr)
WHERE {
    ?source rism:hasIncipit ?incipit ;
            rdfs:label ?title .
    ?incipit a rism:Incipit ;
        	 rism:hasPAEKeysig ?keysigRaw ;
    		 rism:hasPAETimesig ?timesig .
    BIND(REPLACE(STR(?keysigRaw), "\\\\[|\\\\]", "") AS ?keysig) .
    OPTIONAL {
	    VALUES ?binaryK { "c" "c/" "4/4" "2/4" "2/2" "4/2" }
        BIND(?binaryK as ?timesig) .
    }
    OPTIONAL {
	    VALUES ?ternaryK { "3/4" "3/8" "3/2" }
        BIND(?ternaryK as ?timesig) .
    }
    OPTIONAL {
	    VALUES ?compoundK { "6/8" "12/8" "6/4" }
        BIND(?compoundK as ?timesig) .
    }
    #FILTER(STRSTARTS(STR(?title), "Dance"))
}
GROUP BY ?keysig
ORDER BY DESC(?total)

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rism: <https://rism.online/api/v1#>
PREFIX pmo: <http://performedmusicontology.org/ontology/>
PREFIX dcterms: <http://purl.org/dc/terms/>
PREFIX relators: <http://id.loc.gov/vocabulary/relators/>
PREFIX schemaorg: <https://schema.org/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT ?composer ?composer_id ?wiki_id ?picture WHERE {
        ?source a rism:Source ;
        dcterms:creator [ rdfs:label ?composer ] ;
		dcterms:creator ?composer_id .
		BIND(REPLACE(STR(?composer_id), "^https://rism.online/", "") AS ?composer_id_str)
        SERVICE <https://query.wikidata.org/sparql> {
        	?wiki_id wdt:P5504 ?composer_id_str ;
			wdt:P18 ?picture .
        }
}
GROUP BY ?composer_id ?composer ?wiki_id ?picture

PREFIX rism: <https://rism.online/api/v1#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT DISTINCT
  ?person
  ?personLabel
  ?predicate
  ?object
WHERE {
  {
    SELECT DISTINCT ?person ?personLabel
    WHERE {
      ?person a rism:Person .
      FILTER(STRSTARTS(STR(?person), "https://rism.online/people/"))

      OPTIONAL {
        ?person rdfs:label ?personLabel .
      }
    }
    LIMIT 100
  }

  SERVICE <https://virtuoso.simssa.ca/sparql> {
    ?person ?predicate ?object .
  }

  FILTER NOT EXISTS {
    ?person ?predicate ?object .
  }
}
ORDER BY ?person ?predicate

PREFIX dcterms: <http://purl.org/dc/terms/>
PREFIX rdf:    <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs:   <http://www.w3.org/2000/01/rdf-schema#>
PREFIX relators: <http://id.loc.gov/vocabulary/relators/>
PREFIX rism:   <https://rism.online/api/v1#>

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT
  ?url
  ?title
  ?source_type
  ?content_type
  ?record_type
  (GROUP_CONCAT(DISTINCT ?date_statement; separator="; ") AS ?date_statements)
  ?creator_author
  (GROUP_CONCAT(DISTINCT ?other_contrib; separator="; ") AS ?other_contributors)
WHERE {
  # Add some filters here
  #

  ?url a rism:Source .

  # title (prefer @en if present)
  OPTIONAL { ?url rdfs:label ?title_en FILTER(LANG(?title_en) = "en") }
  OPTIONAL { ?url rdfs:label ?title_any }
  BIND(COALESCE(?title_en, ?title_any) AS ?title)

  # record_type (in your example you want "Collection"; map this however your model defines it)
  # Here we derive it from "hasSourceItem" = it contains parts => treat as "Collection".
  BIND(IF(EXISTS { ?url rism:hasSourceItem ?_part }, "Collection", "Item") AS ?record_type)

  # date statements
  OPTIONAL {
    ?url rism:hasDates ?dates .
    OPTIONAL { ?dates rism:dateStatement ?date_statement }
  }

  # creator/author label
  OPTIONAL {
    ?url dcterms:creator ?creator .
    OPTIONAL { ?creator rdfs:label ?creator_label }
  }
  BIND(COALESCE(?creator_label, "") AS ?creator_author)

  # source_type + content_type from material group summaries
  OPTIONAL {
    ?url rism:hasMaterialGroup ?mg .
    ?mg rism:hasSummary ?sumType .
    ?sumType a dcterms:type ;
            rdf:value ?source_type .
  }
  OPTIONAL {
    ?url rism:hasMaterialGroup ?mg2 .
    ?mg2 rism:hasSummary ?sumContent .
    ?sumContent rdfs:label ?ctLabel ;
                rdf:value ?content_type .
    FILTER(LANG(?ctLabel) = "en" && STR(?ctLabel) = "Content type")
  }

  # other contributors: creator + relationships (exclude duplicates if you want)
  {
    # include creator as contributor (matches your desired output)
    BIND(COALESCE(?creator_label, "") AS ?other_contrib)
  }
  UNION
  {
    ?url rism:hasRelationship ?rel .
    ?rel dcterms:relation ?person .
    OPTIONAL { ?person rdfs:label ?person_label }
    BIND(COALESCE(?person_label, "") AS ?other_contrib)
  }
}
GROUP BY
  ?url ?title ?source_type ?content_type ?record_type ?creator_author
LIMIT 10000
